WITH apple AS ( SELECT 'Apple' AS brand_group, SUM(s.product_gms) AS total_sales, SUM(s.shipped_cogs) AS total_cogs, COALESCE(SUM(c.ncrc), 0) AS total_ncrc FROM shipped_raw s LEFT JOIN concession_raw c ON c.asin = s.asin AND c.mapped_year = s.year AND c.mapped_month = s.month AND c.mapped_week = s.week WHERE s.brand_name ILIKE '%Apple%'), samsung AS ( SELECT 'Samsung' AS brand_group, SUM(s.product_gms) AS total_sales, SUM(s.shipped_cogs) AS total_cogs, COALESCE(SUM(c.ncrc), 0) AS total_ncrc FROM shipped_raw s LEFT JOIN concession_raw c ON c.asin = s.asin AND c.mapped_year = s.year AND c.mapped_month = s.month AND c.mapped_week = s.week WHERE s.brand_name ILIKE '%Samsung%') SELECT brand_group, total_sales, total_cogs, total_ncrc, total_sales - total_cogs - total_ncrc AS net_margin FROM (SELECT * FROM apple UNION ALL SELECT * FROM samsung) t;